                            color: currencyType === 'reels' ? 'white' : 'var(--color-text-muted)',
                            display: 'flex', alignItems: 'center', gap: '8px', padding: '10px 24px', borderRadius: '8px', fontWeight: '600', border: 'none'
                        }}
                    >
                        <Film size={18} /> Reels
